from typing import List, Optional


class Solution:
    INT_MIN = -2147483648

    def analyzeSpiritPaths(self, root: Optional["TreeNode"], threshold: int) -> List[int]:
        if root is None:
            return [self.INT_MIN, 0, 0]

        max_val = self.INT_MIN
        count = 0
        has_ge = 0

        def dfs(node, cur_sum: int, prev_neg: bool) -> None:
            nonlocal max_val, count, has_ge
            is_neg = node.val < 0
            # 连续两个负结点，当前路径非法
            if is_neg and prev_neg:
                return

            new_sum = cur_sum + node.val
            is_leaf = node.left is None and node.right is None
            if is_leaf:
                max_val = max(max_val, new_sum)
                count += 1
                if new_sum >= threshold:
                    has_ge = 1
                return

            if node.left is not None:
                dfs(node.left, new_sum, is_neg)
            if node.right is not None:
                dfs(node.right, new_sum, is_neg)

        dfs(root, 0, False)
        if count == 0:
            max_val = self.INT_MIN
        return [max_val, has_ge, count]
```

```java
public class Solution {
    private static final int INT_MIN_VAL = -2147483648;

    private static class State {
        int maxVal = INT_MIN_VAL;
        int count = 0;
        int hasGe = 0;
    }

    public int[] analyzeSpiritPaths(TreeNode root, int threshold) {
        if (root == null) {
            return new int[] {INT_MIN_VAL, 0, 0};
        }
        State st = new State();
        dfs(root, 0L, false, threshold, st);
        if (st.count == 0) {
            st.maxVal = INT_MIN_VAL;
        }
        return new int[] {st.maxVal, st.hasGe, st.count};
    }

    private void dfs(TreeNode node, long curSum, boolean prevNeg, int threshold, State st) {
        boolean isNeg = node.val < 0;
        // 连续负结点则剪枝
        if (isNeg && prevNeg) {
            return;
        }
        long newSum = curSum + node.val;
        boolean isLeaf = node.left == null && node.right == null;
        if (isLeaf) {
            st.maxVal = Math.max(st.maxVal, (int) newSum);
            st.count++;
            if (newSum >= threshold) {
                st.hasGe = 1;
            }
            return;
        }
        if (node.left != null) {
            dfs(node.left, newSum, isNeg, threshold, st);
        }
        if (node.right != null) {
            dfs(node.right, newSum, isNeg, threshold, st);
        }
    }
}
